#include <bits/stdc++.h>
using namespace std;
int main(){
    long long a,b,c,x,y,z,n;
    scanf("%lld:%lld:%lld\n%lld:%lld:%lld\n%lld",&a,&b,&c,&x,&y,&z,&n);
    long long ans=0;
    ans=x*3600+y*60+z-a*3600-b*60-c;
    if(ans<=0){
        cout<<0;
        return 0;
    }else{
        cout<<ans*n;
    }
    return 0;
}
